import React from 'react';
import { Container, Row, Col } from 'react-grid-system';
import Zoom from 'react-medium-image-zoom'
import Kanban from "../images/kanban.png"
import SiteLogo from "../images/sitelogo.png"
import 'react-medium-image-zoom/dist/styles.css'
import { isMobile } from "react-device-detect";
const Projects = () => {


    return(
        <div>
            <Row justify="center">
                <h2 style={{marginBottom: "50px"}}>Projekty, w których brałem udział</h2>
            </Row>
            <Row justify="center" style={{marginBottom: "30px"}}>
                <Col xs={8} md={4}>
                    <div className="image">
                        {isMobile
                        ? <a href={Kanban}><img src={Kanban} width="100" /></a>
                        : <Zoom >
                            <img src={Kanban} width="100" />
                            </Zoom>
                        }
                    </div>
                    <p><h4>Aplikacja</h4>Tablica kanban - projekt w&nbsp;ramach przedmiotu fakultatywnego.</p>
                </Col>
            </Row>

            <Row justify="center" style={{marginBottom: "30px"}}>
                <Col xs={8} md={4}>
                    <img className="image" src={SiteLogo} width="100" />
                    <p><h4>Strona internetowa</h4>Live: <a target="blank" href="https://el-wiedym.pl/">el-wiedym.pl</a></p>
                </Col>
            </Row>

        </div>
    );

}

export default Projects;