import React from 'react';
import { Container, Row, Col } from 'react-grid-system';
import Node from '../images/nodejs.png'
import WebPack from '../images/webpack.png'



const WantTech = () => {


    return(
        <div>
            <Row justify="center">
            <h2 style={{marginBottom: "50px"}}>W przyszłości</h2>
            </Row>
            <Row justify="center">
                
                <Col xs= {3} sm={3} lg={1}><img className="techelement" src={Node} width="60"/></Col>
                <Col xs= {3} sm={3} lg={1}><img className="techelement" src={WebPack} width="60"/></Col>
            </Row>
        </div>
    );

}

export default WantTech;