import React from 'react';
import Mask from '../images/mask.png'
import Menu from '../images/menu.png'
import MenuClose from '../images/menuclose.png'

const NavBar = (props) => {



    return(
        <div className="nav" style={{right: props.active ? "320px" : "0"}}>
            <img src={Mask} alt="Grafika maski Guya Fawkesa" height="40" style={{marginLeft: "30px"}}></img>
            <img src={props.active ? MenuClose : Menu} onClick={() => props.change(!props.active)} alt="Grafika maski Guya Fawkesa" height="40" style={{float: 'right', zIndex: '10', cursor: "pointer", marginRight: "30px"}}></img>
            
        </div>
    );

}

export default NavBar;