import React from 'react';
import { Container, Row, Col } from 'react-grid-system';
import ReactIcon from '../images/react.png'
import Html from '../images/html.png'
import Css from '../images/css.png'
import MySQL from '../images/mysql.png'
import Redux from '../images/redux.png'
import Git from '../images/git.png'
import JS from '../images/js.png'
import JQ from '../images/jq.png'


const MainTech = () => {


    return(
        <div>
            <Row justify="center">
                <h2 style={{marginBottom: "50px"}}>Rozwijam się w</h2>
            </Row>
            <Row justify="center">
                <Col xs= {3} sm={3} lg={1} align="center"><img className="techelement" src={ReactIcon} width="60"/></Col>
                <Col xs= {3} sm={3} lg={1} align="center"><img className="techelement" src={Redux} width="60"/></Col>
                <Col xs= {3} sm={3} lg={1} align="center"><img className="techelement" src={JS} width="60"/></Col>
                <Col xs= {3} sm={3} lg={1} align="center"><img className="techelement" src={JQ} width="60"/></Col>
                <Col xs= {3} sm={3} lg={1} align="center"><img className="techelement" src={Html} width="60"/></Col>
                <Col xs= {3} sm={3} lg={1} align="center"><img className="techelement" src={Css} width="60"/></Col>
                <Col xs= {3} sm={3} lg={1} align="center"><img className="techelement" src={MySQL} width="60"/></Col>
                <Col xs= {3} sm={3} lg={1} align="center"><img className="techelement" src={Git} width="60"/></Col>
            </Row>
        </div>
    );

}

export default MainTech;