import React from 'react';
import { Link } from 'react-scroll'

const SideMenu = (props) => {

    const delay = 200;
    return(
        <div className="menu" style={{right: props.active ? "0" : "-300px"}}>
            <ul>
                <Link to="content" delay={delay} offset={-80} smooth={true} onClick={() => props.change(!props.active)}><li>O mnie</li></Link><hr/>
                <Link to="maintechsection" delay={delay} offset={-80} smooth={true} onClick={() => props.change(!props.active)}><li>Główne technologie</li></Link><hr/>
                <Link to="wanttechsection" delay={delay} offset={-80} smooth={true} onClick={() => props.change(!props.active)}><li>Chcę się nauczyć</li></Link><hr/>
                <Link to="projectssection" delay={delay} offset={-80} smooth={true} onClick={() => props.change(!props.active)}><li>Projekty</li></Link><hr/>
                <Link to="contactsection" delay={delay} offset={-80} smooth={true} onClick={() => props.change(!props.active)}><li>Kontakt</li></Link><hr/>

            </ul>

        </div>
    );

}

export default SideMenu;