import React from 'react';
import { Container, Row, Col } from 'react-grid-system';
import Zoom from 'react-medium-image-zoom'
import Fb from "../images/fb.png"
import Gmail from "../images/gmail.png"
import 'react-medium-image-zoom/dist/styles.css'
import ReactTooltip from "react-tooltip";

const Contact = () => {


    return(
        <div>
            <ReactTooltip/>
            <Row justify="center">
                <h2 style={{marginBottom: "50px"}}>Kontakt</h2>
            </Row>
            <Row justify="center">
                <Col xs= {3} sm={3} lg={1} align="center"><a target="blank" href="https://www.facebook.com/kacper.wozniak.5249/"><img className="techelement contacttile" src={Fb} width="60"/></a></Col>
                <Col xs= {3} sm={3} lg={1} align="center"><a  data-tip="kacper.wozniak155@gmail.com"><img className="techelement contacttile" src={Gmail} width="60"/></a></Col>

            </Row>

        </div>
    );

}

export default Contact;